<script setup lang="ts">
import { File, Image, MapPin, MoreHorizontal, Search, Send, Smile } from 'lucide-vue-next'
import { computed, onMounted, ref } from 'vue'
import { useRouter } from 'vue-router'
import { apiGet, apiPost, apiUpload } from '@/lib/api'
import { useAppStore } from '@/stores/app'
import type { Conversation, Message } from '@/types'

interface FileResponse { id: string; url: string; originalName: string; contentType: string; size: number; provider: string }
const router = useRouter()
const app = useAppStore()
const conversations=ref<Conversation[]>([])
const activeId=ref('')
const text=ref('')
const search=ref('')
const error=ref('')
const imageInput=ref<HTMLInputElement | null>(null)
const fileInput=ref<HTMLInputElement | null>(null)
const fallbackConversation: Conversation = { id: '', name: '消息', avatar: 'https://i.pravatar.cc/160?img=16', type: '好友', unread: 0, lastMessage: '', lastTime: '', online: false, messages: [] }
const filteredConversations=computed(()=>{const keyword=search.value.trim().toLowerCase(); if(!keyword)return conversations.value; return conversations.value.filter(item=>`${item.name}${item.lastMessage}`.toLowerCase().includes(keyword))})
const active=computed(()=>conversations.value.find(c=>c.id===activeId.value) ?? conversations.value[0] ?? fallbackConversation)
async function loadConversations(){try{conversations.value=await apiGet<Conversation[]>('/conversations'); if(!activeId.value && conversations.value.length) activeId.value=conversations.value[0].id}catch(err){error.value=err instanceof Error?err.message:'请先登录后查看消息'}}
function appendMessage(created: Message){const target=conversations.value.find(item=>item.id===active.value.id); if(target){target.messages.push(created);target.lastMessage=created.content || created.type || '';target.lastTime=created.time}}
async function send(){ if(!text.value.trim() || !active.value.id)return; const created=await apiPost<Message>(`/conversations/${active.value.id}/messages`,{type:'TEXT',content:text.value}); appendMessage(created); text.value='' }
function insertEmoji(){text.value = `${text.value}🙂`; app.showToast('已插入表情')}
async function sendLocation(){if(!active.value.id)return; if(!navigator.geolocation){app.showToast('当前浏览器不支持定位');return}; navigator.geolocation.getCurrentPosition(async position=>{const content=`我的位置：${position.coords.latitude.toFixed(5)}, ${position.coords.longitude.toFixed(5)}`; const created=await apiPost<Message>(`/conversations/${active.value.id}/messages`,{type:'LOCATION',content,latitude:position.coords.latitude,longitude:position.coords.longitude}); appendMessage(created); app.showToast('位置已发送')},()=>app.showToast('未获得定位权限'))}
async function uploadAndSend(event: Event, type: 'IMAGE' | 'FILE'){const input=event.target as HTMLInputElement; const file=input.files?.[0]; if(!file||!active.value.id)return; const form=new FormData(); form.append('file',file); try{const uploaded=await apiUpload<FileResponse>('/files/upload',form); const created=await apiPost<Message>(`/conversations/${active.value.id}/messages`,{type,content:type==='IMAGE'?'[图片]':uploaded.originalName,mediaUrl:uploaded.url}); appendMessage(created); app.showToast(type==='IMAGE'?'图片已发送':'文件已发送')}catch(err){app.showToast(err instanceof Error?err.message:'发送失败')}finally{input.value=''}}
function openInfo(){app.showToast(active.value.type==='小队'?'小队公告、文件和相册入口已在小队页提供':'好友资料页将在好友体系完善后开放')}
function openProfile(){router.push(active.value.type==='小队'?'/teams':'/profile')}
onMounted(loadConversations)
</script>
<template><div class="container messages-page"><p v-if="error" class="form-error">{{ error }}</p><input ref="imageInput" class="hidden-file" type="file" accept="image/*" @change="uploadAndSend($event,'IMAGE')" /><input ref="fileInput" class="hidden-file" type="file" @change="uploadAndSend($event,'FILE')" /><div class="chat-shell"><aside class="conversation-list"><div class="chat-title"><h1>消息</h1><button @click="openInfo"><MoreHorizontal /></button></div><div class="chat-search"><Search :size="16" /><input v-model="search" placeholder="搜索联系人或小队" /></div><div class="conversations"><button v-for="item in filteredConversations" :key="item.id" :class="{active:item.id===activeId}" @click="activeId=item.id"><span class="avatar"><img :src="item.avatar" /><i v-if="item.online"></i></span><span class="conversation-copy"><b>{{ item.name }}<small>{{ item.lastTime }}</small></b><em>{{ item.lastMessage }}</em></span><strong v-if="item.unread">{{ item.unread }}</strong></button></div></aside><main class="chat-main"><header><div><img :src="active.avatar" /><span><b>{{ active.name }}</b><small>{{ active.type==='小队'?'小队群聊':'好友会话' }}</small></span></div><button @click="openInfo"><MoreHorizontal /></button></header><div class="messages"><div class="date-divider">今天</div><div v-if="active.type==='小队'" class="announcement">群公告会在这里展示。</div><div v-for="message in active.messages" :key="message.id" :class="['message',{mine:message.mine}]"><img v-if="!message.mine" src="https://i.pravatar.cc/80?img=45" /><div><p>{{ message.recalled ? '消息已撤回' : message.content }}</p><span>{{ message.time }} {{ message.mine?(message.read?'已读':'未读'):'' }}</span></div></div><div v-if="!active.messages.length" class="no-messages">还没有消息</div></div><div class="composer"><div class="compose-tools"><button @click="insertEmoji"><Smile :size="19" /></button><button @click="imageInput?.click()"><Image :size="19" /></button><button @click="fileInput?.click()"><File :size="19" /></button><button @click="sendLocation"><MapPin :size="19" /></button></div><div class="compose-input"><textarea v-model="text" placeholder="输入消息，按 Enter 发送" @keydown.enter.prevent="send"></textarea><button :disabled="!text.trim()" @click="send"><Send :size="18" /></button></div></div></main><aside class="chat-info"><img :src="active.avatar" /><h3>{{ active.name }}</h3><p>{{ active.type==='小队'?'小队成员可以发送文字、图片、文件和位置。':'好友之间可以即时沟通。' }}</p><div><span>消息免打扰 <input type="checkbox" /></span><span>置顶会话 <input type="checkbox" checked /></span></div><button @click="openProfile">查看{{ active.type==='小队'?'小队主页':'个人主页' }}</button></aside></div></div></template>
<style scoped>
.messages-page{padding:30px 0 60px}.hidden-file{display:none}.chat-shell{height:720px;overflow:hidden;background:#fff;border:1px solid var(--color-line);border-radius:var(--radius-lg);box-shadow:var(--shadow-soft);display:grid;grid-template-columns:290px 1fr 230px}.conversation-list{border-right:1px solid var(--color-line)}.chat-title{height:70px;padding:0 20px;display:flex;align-items:center;justify-content:space-between}.chat-title h1{margin:0;font-size:24px}.chat-title button,.chat-main header button{border:0;background:none}.chat-search{margin:0 14px 12px;padding:9px 11px;background:var(--color-bg);border-radius:9px;display:flex;align-items:center;gap:7px}.chat-search input{min-width:0;flex:1;border:0;background:none;outline:0;font-size:11px}.conversations button{position:relative;width:100%;padding:13px 14px;border:0;background:#fff;display:flex;align-items:center;gap:10px;text-align:left}.conversations button.active{background:var(--color-primary-soft)}.avatar{position:relative}.avatar img{width:44px;height:44px;border-radius:13px;object-fit:cover}.avatar i{position:absolute;right:-1px;bottom:-1px;width:10px;height:10px;border:2px solid #fff;border-radius:50%;background:var(--color-mint)}.conversation-copy{min-width:0;flex:1}.conversation-copy b{display:flex;justify-content:space-between;font-size:12px}.conversation-copy small{color:var(--color-ink-soft);font-size:8px;font-weight:400}.conversation-copy em{display:block;margin-top:6px;overflow:hidden;white-space:nowrap;text-overflow:ellipsis;color:var(--color-ink-soft);font-size:9px;font-style:normal}.conversations strong{position:absolute;right:14px;bottom:11px;min-width:16px;height:16px;padding:0 4px;border-radius:8px;background:var(--color-primary);color:#fff;font-size:8px;display:grid;place-items:center}.chat-main{min-width:0;display:flex;flex-direction:column;background:#faf9f7}.chat-main header{height:70px;padding:0 20px;border-bottom:1px solid var(--color-line);background:#fff;display:flex;align-items:center;justify-content:space-between}.chat-main header>div{display:flex;align-items:center;gap:10px}.chat-main header img{width:38px;height:38px;border-radius:10px;object-fit:cover}.chat-main header span{display:flex;flex-direction:column;font-size:12px}.chat-main header small{margin-top:4px;color:var(--color-mint);font-size:8px}.messages{flex:1;padding:18px 26px;overflow:auto}.date-divider{text-align:center;color:var(--color-ink-soft);font-size:8px}.announcement{margin:14px auto 25px;padding:9px 12px;width:max-content;max-width:90%;border-radius:8px;background:#ece9e3;color:var(--color-ink-soft);font-size:9px}.message{margin:16px 0;display:flex;gap:8px}.message>img{width:30px;height:30px;border-radius:9px}.message>div{max-width:70%}.message p{margin:0;padding:10px 13px;border-radius:4px 13px 13px 13px;background:#fff;box-shadow:0 3px 12px rgba(23,34,56,.06);font-size:11px;line-height:1.6}.message span{display:block;margin-top:4px;color:#a4a8b0;font-size:7px}.message.mine{justify-content:flex-end;text-align:right}.message.mine p{background:var(--color-primary);color:#fff;border-radius:13px 4px 13px 13px;text-align:left}.no-messages{text-align:center;margin-top:120px;color:var(--color-ink-soft);font-size:12px}.composer{padding:12px 18px 18px;border-top:1px solid var(--color-line);background:#fff}.compose-tools{display:flex;gap:3px;margin-bottom:7px}.compose-tools button{border:0;background:none;color:var(--color-ink-soft)}.compose-input{display:flex;gap:8px}.compose-input textarea{height:55px;flex:1;padding:9px;border:0;background:var(--color-bg);border-radius:9px;resize:none;outline:0;font-size:11px}.compose-input>button{width:42px;border:0;border-radius:10px;background:var(--color-primary);color:#fff}.compose-input>button:disabled{opacity:.4}.chat-info{padding:28px 20px;border-left:1px solid var(--color-line);text-align:center}.chat-info>img{width:70px;height:70px;margin:auto;border-radius:18px;object-fit:cover}.chat-info h3{margin:13px 0 7px}.chat-info>p{color:var(--color-ink-soft);font-size:10px;line-height:1.6}.chat-info>div{margin:25px 0;border-top:1px solid var(--color-line)}.chat-info>div span{padding:12px 0;border-bottom:1px solid var(--color-line);display:flex;justify-content:space-between;font-size:10px}.chat-info>button{padding:9px 13px;border:1px solid var(--color-line);border-radius:8px;background:#fff;font-size:10px}
@media(max-width:900px){.chat-shell{grid-template-columns:250px 1fr}.chat-info{display:none}}@media(max-width:650px){.chat-shell{height:calc(100vh - 130px);grid-template-columns:76px 1fr}.chat-title h1,.chat-search,.conversation-copy,.conversations strong{display:none}.chat-title{justify-content:center}.conversations button{justify-content:center}.conversation-list{min-width:0}.messages{padding:14px}.message>div{max-width:85%}}
</style>
